('additional-maths:8-2-tangents-and-normals:mcq:1f6723fa', 'additional-maths', 'additional-maths:8-2-tangents-and-normals', '8.2 Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "Differentiating \\( y = x^3 - 2x + 3 \\) gives \\( \\frac{dy}{dx} = \\)", "options": ["\\( 3x^2 - 2 \\)", "\\( 3x^2 - 2x \\)", "\\( x^2 - 2 \\)", "\\( 3x^3 - 2 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\frac{d}{dx}(x^3) = 3x^2 \\), \\( \\frac{d}{dx}(-2x) = -2 \\), and the constant \\( 3 \\) differentiates to \\( 0 \\)."}'::jsonb),
('additional-maths:8-2-tangents-and-normals:mcq:74ea788e', 'additional-maths', 'additional-maths:8-2-tangents-and-normals', '8.2 Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "For \\( y = x^2 - 3x + 4 \\), the gradient of the tangent at the point where \\( x = 3 \\) is:", "options": ["\\( 3 \\)", "\\( 2x - 3 \\)", "\\( 4 \\)", "\\( 9 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\frac{dy}{dx} = 2x - 3 \\); at \\( x = 3 \\) this is \\( 2(3) - 3 = 3 \\). The gradient is a number, not the function \\( 2x - 3 \\)."}'::jsonb),
('additional-maths:8-2-tangents-and-normals:mcq:eba32c71', 'additional-maths', 'additional-maths:8-2-tangents-and-normals', '8.2 Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "The tangent to a curve at a point has gradient \\( 4 \\). The gradient of the normal there is:", "options": ["\\( -\\tfrac{1}{4} \\)", "\\( 4 \\)", "\\( \\tfrac{1}{4} \\)", "\\( 4 \\times (-1) = -4 \\)"]}'::jsonb, '{"answer": 0, "explain": "Normal gradient \\( = -\\frac{1}{m} = -\\frac{1}{4} \\); it is the negative reciprocal, not the same as \\( m \\)."}'::jsonb),
('additional-maths:8-2-tangents-and-normals:mcq:f5540b14', 'additional-maths', 'additional-maths:8-2-tangents-and-normals', '8.2 Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "The tangent to \\( y = x^2 \\) at \\( (2,\\ 4) \\) is:", "options": ["\\( y = 4x - 4 \\)", "\\( y = 2x \\)", "\\( y = 4x \\)", "\\( y = 2x - 4 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\frac{dy}{dx} = 2x = 4 \\) at \\( x = 2 \\); then \\( y - 4 = 4(x - 2) \\Rightarrow y = 4x - 4 \\). Writing \\( y = 2x \\) mistakes the gradient function for the equation."}'::jsonb),
('additional-maths:8-2-tangents-and-normals:mcq:1f9c7fdb', 'additional-maths', 'additional-maths:8-2-tangents-and-normals', '8.2 Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "A student finds \\( \\frac{dy}{dx} = 2x \\) for \\( y = x^2 + 1 \\) and writes the tangent at \\( (2,\\ 5) \\) as \\( y = 2x \\). This is wrong because:", "options": ["\\( \\frac{dy}{dx} \\) is the gradient function, not the equation", "the curve is not \\( x^2 + 1 \\)", "the point is not on the curve", "the constant \\( +1 \\) was dropped, so it should be \\( y = 2x + 1 \\)"]}'::jsonb, '{"answer": 0, "explain": "You must evaluate \\( \\frac{dy}{dx} \\) at \\( x = 2 \\) (giving \\( 4 \\)) and then use \\( y - 5 = 4(x - 2) \\Rightarrow y = 4x - 3 \\)."}'::jsonb),
('additional-maths:8-2-tangents-and-normals:mcq:7d35c33f', 'additional-maths', 'additional-maths:8-2-tangents-and-normals', '8.2 Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "The normal to \\( y = x^3 - 2x + 3 \\) at \\( (1,\\ 2) \\) is:", "options": ["\\( y = -x + 3 \\)", "\\( y = x + 1 \\)", "\\( y = -x + 2 \\)", "\\( y = 3x^2 - 2 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\frac{dy}{dx} = 3x^2 - 2 = 1 \\) at \\( x = 1 \\); normal gradient \\( = -1 \\); \\( y - 2 = -1(x - 1) \\Rightarrow y = -x + 3 \\)."}'::jsonb),
('additional-maths:8-2-tangents-and-normals:mcq:6862e21d', 'additional-maths', 'additional-maths:8-2-tangents-and-normals', '8.2 Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "Which line form is best for writing a tangent or normal through a known point?", "options": ["\\( y - y_1 = m(x - x_1) \\)", "\\( y = mx + c \\), then substitute to find \\( c \\)", "\\( ax + by + c = 0 \\)", "\\( \\frac{dy}{dx} = m \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( y - y_1 = m(x - x_1) \\) substitutes the point directly and avoids a separate step to find \\( c \\)."}'::jsonb),
('additional-maths:8-2-tangents-and-normals:mcq:2c229950', 'additional-maths', 'additional-maths:8-2-tangents-and-normals', '8.2 Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "A tangent has gradient \\( 5 \\) and passes through \\( (2,\\ 3) \\). Using \\( y = mx + c \\), the value of \\( c \\) is:", "options": ["\\( -7 \\)", "\\( 3 \\)", "\\( 13 \\)", "\\( 5 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( 3 = 5(2) + c \\Rightarrow c = 3 - 10 = -7 \\). Leaving \\( c = 3 \\) forgets to substitute the point."}'::jsonb),
('additional-maths:8-2-tangents-and-normals:mcq:09b9448b', 'additional-maths', 'additional-maths:8-2-tangents-and-normals', '8.2 Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "For \\( y = \\tfrac{1}{2}x^2 - 2x \\), the tangent gradient at the origin \\( (0,\\ 0) \\) is:", "options": ["\\( -2 \\)", "\\( 0 \\)", "\\( 2 \\)", "\\( \\tfrac{1}{2} \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\frac{dy}{dx} = x - 2 \\); at \\( x = 0 \\) this is \\( -2 \\)."}'::jsonb),
('additional-maths:8-2-tangents-and-normals:mcq:fca42ca3', 'additional-maths', 'additional-maths:8-2-tangents-and-normals', '8.2 Tangents and Normals', 'mcq', 'mcq', 1, '{"question": "The curve \\( y = \\tfrac{1}{2}x^2 - 2x \\) crosses the \\( x \\)-axis (apart from the origin) at:", "options": ["\\( (4,\\ 0) \\)", "\\( (2,\\ 0) \\)", "\\( (-4,\\ 0) \\)", "\\( (1,\\ 0) \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\tfrac{1}{2}x^2 - 2x = 0 \\Rightarrow x(\\tfrac{1}{2}x - 2) = 0 \\Rightarrow x = 0 \\) or \\( x = 4 \\)."}'::jsonb),
