('additional-maths:8-3-stationary-points-and-curve-sketching:tf:a8aac4cb', 'additional-maths', 'additional-maths:8-3-stationary-points-and-curve-sketching', '8.3 Stationary Points and Curve Sketching', 'tf', 'tf', 1, '{"question": "If \\( \\frac{d^2y}{dx^2} = 0 \\) at a stationary point, it must be a point of inflection."}'::jsonb, '{"answer": false, "explain": "\\( \\frac{d^2y}{dx^2} = 0 \\) is inconclusive; you must check the gradient sign either side to decide the nature."}'::jsonb),
('additional-maths:8-3-stationary-points-and-curve-sketching:tf:396c0e41', 'additional-maths', 'additional-maths:8-3-stationary-points-and-curve-sketching', '8.3 Stationary Points and Curve Sketching', 'tf', 'tf', 1, '{"question": "Writing ''\\( \\frac{d^2y}{dx^2} > 0 \\)'' on its own fully answers a ''determine the nature'' question."}'::jsonb, '{"answer": false, "explain": "You must also state the conclusion (''so it is a minimum''); the sign without a conclusion loses the ''determine'' mark."}'::jsonb),
('additional-maths:8-3-stationary-points-and-curve-sketching:tf:9c435412', 'additional-maths', 'additional-maths:8-3-stationary-points-and-curve-sketching', '8.3 Stationary Points and Curve Sketching', 'tf', 'tf', 1, '{"question": "A cubic curve can have at most two stationary points."}'::jsonb, '{"answer": true, "explain": "Differentiating a cubic gives a quadratic \\( \\frac{dy}{dx} \\), which has at most two roots, so at most two stationary points."}'::jsonb),
('additional-maths:8-3-stationary-points-and-curve-sketching:tf:0378c60d', 'additional-maths', 'additional-maths:8-3-stationary-points-and-curve-sketching', '8.3 Stationary Points and Curve Sketching', 'tf', 'tf', 1, '{"question": "The \\( y \\)-coordinate of a stationary point is found by substituting its \\( x \\)-value into the original equation of the curve."}'::jsonb, '{"answer": true, "explain": "The point lies on the curve, so substitute \\( x \\) into \\( y = \\ldots \\), not into \\( \\frac{dy}{dx} \\)."}'::jsonb),
('additional-maths:8-3-stationary-points-and-curve-sketching:learn:97dfc16b', 'additional-maths', 'additional-maths:8-3-stationary-points-and-curve-sketching', '8.3 Stationary Points and Curve Sketching', 'learn', 'mcq', 1, '{"readingTitle": "What is a stationary point, and how do you find one?", "reading": "<p>A <strong>stationary point</strong> is a point on a curve where the gradient is momentarily zero — the curve has flattened out. Because the gradient function is \\( \\frac{dy}{dx} \\), a stationary point occurs exactly where \\[ \\frac{dy}{dx} = 0. \\]</p>\n            <p>The method is always the same:</p>\n            <ul>\n              <li><strong>Differentiate</strong> to get \\( \\frac{dy}{dx} \\).</li>\n              <li><strong>Set \\( \\frac{dy}{dx} = 0 \\)</strong> and solve for \\( x \\).</li>\n              <li><strong>Substitute each \\( x \\) back into the original curve</strong> \\( y = \\ldots \\) to get the matching \\( y \\).</li>\n              <li><strong>Give the answer as coordinate pairs</strong> \\( (x,\\ y) \\) — an \\( x \\)-value on its own is an incomplete answer and loses the final mark.</li>\n            </ul>\n            <p><strong>Worked example — find the stationary points of \\( y = x^3 - 3x^2 - 9x + 5 \\):</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Differentiate: \\( \\frac{dy}{dx} = 3x^2 - 6x - 9 \\).</td></tr>\n              <tr><td>2. Set to zero: \\( 3x^2 - 6x - 9 = 0 \\Rightarrow 3(x^2 - 2x - 3) = 0 \\Rightarrow 3(x-3)(x+1) = 0 \\).</td></tr>\n              <tr><td>3. Solve: \\( x = 3 \\) or \\( x = -1 \\).</td></tr>\n              <tr><td>4. Substitute back: \\( x=3:\\ y = 27 - 27 - 27 + 5 = -22 \\); \\( x=-1:\\ y = -1 - 3 + 9 + 5 = 10 \\).</td></tr>\n              <tr><td>5. Stationary points: \\[ (3,\\ -22) \\quad\\text{and}\\quad (-1,\\ 10). \\]</td></tr>\n            </table>", "question": "The curve \\( y = x^2 - 6x + 5 \\) has a stationary point. At what value of \\( x \\)?", "options": ["\\( x = 3 \\)", "\\( x = -3 \\)", "\\( x = 6 \\)", "\\( x = 5 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\frac{dy}{dx} = 2x - 6 = 0 \\Rightarrow x = 3 \\)."}'::jsonb)
